const express = require('express');
const bodyParser = require('body-parser');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(bodyParser.json());

const plugins = [];

function loadPlugins() {
    const pluginDir = process.env.PLUGIN_DIR || './plugins';
    const pluginFiles = fs.readdirSync(pluginDir);

    pluginFiles.forEach(file => {
        const filePath = path.join(pluginDir, file);
        const pluginCode = fs.readFileSync(filePath, 'utf-8');
        const plugin = eval(`(${pluginCode})`); // Ensure plugins export a function
        plugins.push(plugin);
    });
}

function applyPlugins(req, res, next) {
    plugins.forEach(plugin => {
        if (typeof plugin === 'function') {
            plugin(req, res);
        }
    });
    next();
}

app.use(applyPlugins);

app.get('/api/resource', (req, res) => {
    res.json({ message: 'Hello from API Gateway!' });
});

loadPlugins();

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`API Gateway running on port ${PORT}`);
});